// // This module compares two 8-bit inputs and outputs high if the first input is less than or equal to the second input.
module comparator_8bit (
    input [7:0] in0,
    input [7:0] in1,
    output reg out
);

always @(*) begin
    if (in0 > in1)
        out = 1;
    else
        out = 0;
end

endmodule
